  public Iterable<TargetLink> getPlacesForNewTarget(SNode parent, SAbstractConcept expectedConcept, Runnable scopeQuery) {

    List<AbstractModelReadEvent> readEvents = collectAccessEvents(SNodeOperations.getModel(parent), scopeQuery);
    Set<SNode> accessedNodes = SetSequence.fromSetWithValues(new HashSet<SNode>(), ListSequence.fromList(readEvents).ofType(SNodeReadEvent.class).select((it) -> it.getNode()));

    Set<TargetLink> result = SetSequence.fromSet(new HashSet<TargetLink>());
    for (SNode accessedNode : SetSequence.fromSet(accessedNodes)) {
      // new target can be added as a sibling
      final SContainmentLink accessedLink = accessedNode.getContainmentLink();
      if (accessedLink != null) {
        if (accessedLink.isMultiple()) {
          TargetLink place = new TargetLink(SNodeOperations.getParent(accessedNode), accessedLink);
          if (Sequence.fromIterable(place.getPossibleConcepts(expectedConcept)).any((it) -> it.isSubConceptOf(accessedLink.getTargetConcept()))) {
            SetSequence.fromSet(result).addElement(place);
          }
        }
      }

      // MPS does not fire events for reads on empty child collections. We have to search for applicable child links.
      for (final SContainmentLink childLink : CollectionSequence.fromCollection(SNodeOperations.getConcept(accessedNode).getContainmentLinks())) {
        Iterable<? extends SNode> children = accessedNode.getChildren(childLink);
        if (Sequence.fromIterable(children).isEmpty()) {
          // If it is not empty, the link will be handled by the first case

          TargetLink place = new TargetLink(accessedNode, childLink);
          if (childLink.isMultiple() && Sequence.fromIterable(place.getPossibleConcepts(expectedConcept)).any((it) -> it.isSubConceptOf(childLink.getTargetConcept()))) {
            SetSequence.fromSet(result).addElement(place);
          }
        }
      }
    }

    return result;
  }

  public List<AbstractModelReadEvent> collectAccessEvents(SModel eventSource, Runnable modelReader) {
    final List<AbstractModelReadEvent> events = ListSequence.fromList(new ArrayList<AbstractModelReadEvent>());
    final SNodeAccessListener listener = new SNodeAccessListener() {
      public void nodeRead(@NotNull SNodeReadEvent event) {
        ListSequence.fromList(events).addElement(event);
      }
      public void propertyRead(@NotNull SPropertyReadEvent event) {
        ListSequence.fromList(events).addElement(event);
      }
      public void referenceRead(@NotNull SReferenceReadEvent event) {
        ListSequence.fromList(events).addElement(event);
      }
    };
    eventSource.addAccessListener(listener);
    try {
      modelReader.run();
    } finally {
      eventSource.removeAccessListener(listener);
    }
    return events;
  }

