  public Iterable<SConcept> findApplicableConceptsForSubstitution(@NotNull SNode nodeToSubstitute) {
    Set<SLanguage> importedLangs = new SLanguageHierarchy(SModelOperations.getAllLanguageImports(SNodeOperations.getModel(nodeToSubstitute))).getExtended();
    SContainmentLink containmentLink = nodeToSubstitute.getContainmentLink();
    if (containmentLink == null) {
      return Sequence.fromIterable(Collections.<SConcept>emptyList());
    }
    SAbstractConcept childConcept = containmentLink.getTargetConcept();
    final Set<SAbstractConcept> desc = ConceptDescendantsCache.getInstance().getDescendants(childConcept);
    List<SConcept> concepts = new ArrayList<SConcept>();
    for (SAbstractConcept concept : desc) {
      if (!(concept instanceof SConcept)) {
        continue;
      }
      if (!(importedLangs.contains(concept.getLanguage()))) {
        continue;
      }
      concepts.add((SConcept) concept);
    }
    return concepts;
  }

